#include<bits/stdc++.h>
using namespace std;
int a[1010];
map<int,int> mp;
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,sum=0;
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
            sum+=a[i];
        }
        if(sum%n!=0)
        {
            printf("No\n");
            continue;
        }
        sum/=n;
        for(int i=1;i<=n;i++)
        {
            a[i]-=sum;
        }
        int flag=0;
        for(int _=1;_<=1000;_++)
        {
            random_shuffle(a+1,a+1+n);
            int sum=0;
            mp.clear();
            for(int i=1;i<=n;i++)
            {
                sum+=a[i];
                if((i!=n&&sum==0)||mp[sum])
                {
                    flag=1;
                    break;
                }
                mp[sum]=1;
            }
            if(flag)
            {
                break;
            }
        }
        if(flag)
        {
            printf("Yes\n");
        }
        else
        {
            printf("No\n");
        }
    }
    return 0;
}
